import React from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider } from './context/AuthContext';
import ProtectedRoute from './routes/ProtectedRoutes';
import AdminLayout from './layouts/AdminLayout';
import { StyledEngineProvider } from '@mui/material/styles';
// Pages (আগের তৈরি করা কম্পোনেন্টগুলো এখানে ইম্পোর্ট করবেন)
import Login from './pages/Login';
import HQDashboard from './pages/HQDashboard';
import POS from './pages/POSTerminal';
import MasterMenuItem from './pages/MasterMenuItem';
import OutletProducts from './pages/OutletProduct';

export default function App() {
  return (
    <StyledEngineProvider injectFirst>
      <AuthProvider>
        <BrowserRouter>
          <Routes>
            {/* পাবলিক রাউট */}
            <Route path="/login" element={<Login />} />

            {/* প্রোটেক্টেড রাউটস */}
            <Route element={<ProtectedRoute />}>
              <Route element={<AdminLayout />}>
                {/* ডিফল্ট রাউট রিডাইরেক্ট */}
                {/* <Route
                  path="/"
                  element={<Navigate to="/hq-dashboard" replace />}
                /> */}

                <Route path="/hq-dashboard" element={<HQDashboard />} />
                <Route path="/master-menu" element={<MasterMenuItem />} />
                <Route path="/outlet-products" element={<OutletProducts />} />

                {/* POS পেজে outletId প্রপস হিসেবে পাঠাতে পারেন অথবা AuthContext এর user.outlet_id থেকে নিতে পারেন */}
                <Route path="/pos" element={<POS outletId={1} />} />
              </Route>
            </Route>

            {/* 404 Page (Optional) */}
            <Route path="*" element={<Navigate to="/" replace />} />
          </Routes>
        </BrowserRouter>
      </AuthProvider>
    </StyledEngineProvider>
  );
}
